# Homebrew formula for Icebox — Rust TUI Kanban Board with AI Sidebar
#
# Install:  brew tap SteelCrab/tap && brew install icebox
# Upgrade:  brew upgrade icebox
#
# Auto-generated by GitHub Actions in SteelCrab/icebox on every v* tag push.

class Icebox < Formula
  desc "Rust TUI Kanban Board with AI Sidebar"
  homepage "https://github.com/SteelCrab/icebox"
  version "0.4.0"
  license "Apache-2.0"

  on_macos do
    on_arm do
      url "https://github.com/SteelCrab/icebox/releases/download/v0.4.0/icebox-aarch64-apple-darwin.tar.gz"
      sha256 "f3afcf54889888aaf4de9cc5c97ae31ac19b99fc389cb31485d46903a99e558d"
    end
  end

  def install
    bin.install "icebox"
  end

  test do
    assert_match "icebox", shell_output("#{bin}/icebox help")
  end
end
